      this.atomicWrite(routePath, JSON.stringify(route, null, 2));
    }
  } catch { /* best-effort: session dir may not exist */ }
}

saveDiffArtifact(sessionId: string, round: number, diff: DiffResult): void {
  try {
    const diffsDir = path.join(this.sessionsDir, sessionId, 'diffs');
    fs.mkdirSync(diffsDir, { recursive: true });
    const diffPath = path.join(diffsDir, `round-${round}.json`);
    this.atomicWrite(diffPath, JSON.stringify(diff, null, 2));
  } catch { /* best-effort */ }
}
```

**效果**：
- `sessionIdRef.current` 为 null → 跳过持久化，会话正常继续
- 文件系统异常 → catch 吞掉，会话正常继续
- 与现有 `App.tsx:419`/`444`/`712` 的 best-effort 模式完全一致
- diff/choiceRoute 丢失 = graceful degradation（reviewer prompt 显示 non-git 提示 / choice forward 丢失回退到普通审查）

